<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Maze Pathfinding Bots</title>
    <style>
        body {
            background: #2c3e50;
            color: #ecf0f1;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            margin: 0;
            height: 100vh;
            overflow: hidden;
        }
        #hud {
            margin-bottom: 15px;
            text-align: center;
        }
        .stat {
            font-size: 24px;
            font-weight: bold;
            margin: 0 20px;
            display: inline-block;
        }
        #maze {
            background: #34495e;
            border: 8px solid #1a252f;
            box-shadow: 0 0 20px rgba(0,0,0,0.5);
            display: block;
        }
        #reset {
            margin-top: 20px;
            padding: 10px 30px;
            font-size: 18px;
            cursor: pointer;
            background: #e74c3c;
            color: white;
            border: none;
            border-radius: 5px;
            transition: background 0.2s;
        }
        #reset:hover {
            background: #c0392b;
        }
    </style>
</head>
<body>

<div id="hud">
    <span id="completed">Completed: 0/24</span>
    <span id="timer">Time: 0s</span>
</div>

<canvas id="maze" width="500" height="500"></canvas>

<button id="reset">Reset Game</button>

<script>
(function() {
    const canvas = document.getElementById('maze');
    const ctx = canvas.getContext('2d');
    const completedEl = document.getElementById('completed');
    const timerEl = document.getElementById('timer');
    const resetBtn = document.getElementById('reset');

    const GRID_SIZE = 20;
    const CELL_SIZE = canvas.width / GRID_SIZE;
    const BOT_COUNT = 24;

    class MazeGame {
        constructor() {
            this.bots = [];
            this.completed = 0;
            this.elapsedMs = 0;
            this.grid = [];
            this.path = [];
            this.spawnX = 0;
            this.spawnY = 0;
            this.exitX = GRID_SIZE - 1;
            this.exitY = GRID_SIZE - 1;
            this.reset();
        }

        reset() {
            this.elapsedMs = 0;
            this.completed = 0;
            this.generateMaze();
            this.path = this.findPath(this.spawnX, this.spawnY, this.exitX, this.exitY);
            this.bots = Array.from({ length: BOT_COUNT }, (_, i) => ({
                x: this.spawnX,
                y: this.spawnY,
                delay: i * 4, // Staggered start to avoid "blob" movement
                pathIndex: 0,
                finished: false
            }));
            this.updateUI();
        }

        generateMaze() {
            // Initialize grid with all walls present
            this.grid = Array.from({ length: GRID_SIZE }, () =>
                Array.from({ length: GRID_SIZE }, () => ({
                    walls: { top: true, right: true, bottom: true, left: true },
                    visited: false
                }))
            );

            const stack = [];
            const startCell = { x: 0, y: 0 };
            this.grid[0][0].visited = true;
            stack.push(startCell);

            while (stack.length > 0) {
                const current = stack[stack.length - 1];
                const neighbors = [];

                const dirs = [
                    { dx: 0, dy: -1, wall: 'top', opp: 'bottom' },
                    { dx: 1, dy: 0, wall: 'right', opp: 'left' },
                    { dx: 0, dy: 1, wall: 'bottom', opp: 'top' },
                    { dx: -1, dy: 0, wall: 'left', opp: 'right' }
                ];

                for (const { dx, dy, wall, opp } of dirs) {
                    const nx = current.x + dx;
                    const ny = current.y + dy;
                    if (nx >= 0 && nx < GRID_SIZE && ny >= 0 && ny < GRID_SIZE && !this.grid[ny][nx].visited) {
                        neighbors.push({ nx, ny, wall, opp });
                    }
                }

                if (neighbors.length > 0) {
                    const { nx, ny, wall, opp } = neighbors[Math.floor(Math.random() * neighbors.length)];
                    this.grid[current.y][current.x].walls[wall] = false;
                    this.grid[ny][nx].walls[opp] = false;
                    this.grid[ny][nx].visited = true;
                    stack.push({ x: nx, y: ny });
                } else {
                    stack.pop();
                }
            }
        }

        findPath(sx, sy, ex, ey) {
            const queue = [[sx, sy, []]];
            const visited = new Set([`${sx},${sy}`]);

            while (queue.length > 0) {
                const [cx, cy, path] = queue.shift();
                const currentPath = [...path, { x: cx, y: cy }];

                if (cx === ex && cy === ey) return currentPath;

                const dirs = [
                    { dx: 0, dy: -1, wall: 'top' },
                    { dx: 1, dy: 0, wall: 'right' },
                    { dx: 0, dy: 1, wall: 'bottom' },
                    { dx: -1, dy: 0, wall: 'left' }
                ];

                for (const { dx, dy, wall } of dirs) {
                    const nx = cx + dx;
                    const ny = cy + dy;
                    if (nx >= 0 && nx < GRID_SIZE && ny >= 0 && ny < GRID_SIZE) {
                        if (!this.grid[cy][cx].walls[wall] && !visited.has(`${nx},${ny}`)) {
                            visited.add(`${nx},${ny}`);
                            queue.push([nx, ny, currentPath]);
                        }
                    }
                }
            }
            return []; // Should not happen in a perfect maze
        }

        tick(n) {
            for (let i = 0; i < n; i++) {
                this.elapsedMs += 16; // Fixed step for determinism
                let completedCount = 0;

                this.bots.forEach(bot => {
                    if (!bot.finished) {
                        if (bot.delay > 0) {
                            bot.delay--;
                        } else {
                            bot.pathIndex++;
                            const nextCell = this.path[bot.pathIndex];
                            if (nextCell) {
                                bot.x = nextCell.x;
                                bot.y = nextCell.y;
                                if (bot.x === this.exitX && bot.y === this.exitY) {
                                    bot.finished = true;
                                }
                            }
                        }
                    }
                    if (bot.finished) completedCount++;
                });
                this.completed = completedCount;
            }
            this.updateUI();
        }

        updateUI() {
            completedEl.textContent = `Completed: ${this.completed}/${BOT_COUNT}`;
            timerEl.textContent = `Time: ${Math.floor(this.elapsedMs / 1000)}s`;
        }

        render() {
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            // Draw Walls
            ctx.strokeStyle = "#ecf0f1";
            ctx.lineWidth = 2;
            for (let y = 0; y < GRID_SIZE; y++) {
                for (let x = 0; x < GRID_SIZE; x++) {
                    const cell = this.grid[y][x];
                    const px = x * CELL_SIZE;
                    const py = y * CELL_SIZE;

                    ctx.beginPath();
                    if (cell.walls.top) { ctx.moveTo(px, py); ctx.lineTo(px + CELL_SIZE, py); }
                    if (cell.walls.right) { ctx.moveTo(px + CELL_SIZE, py); ctx.lineTo(px + CELL_SIZE, py + CELL_SIZE); }
                    if (cell.walls.bottom) { ctx.moveTo(px, py + CELL_SIZE); ctx.lineTo(px + CELL_SIZE, py + CELL_SIZE); }
                    if (elseIf = cell.walls.left) { ctx.moveTo(px, py); ctx.lineTo(px, py + CELL_SIZE); }
                    ctx.stroke();
                }
            }

            // Draw Exit/Spawn
            ctx.fillStyle = "rgba(46, 204, 113, 0.3)"; // Green exit
            ctx.fillRect(this.exitX * CELL_SIZE, this.exitY * CELL_SIZE, CELL_SIZE, CELL_SIZE);
            ctx.fillStyle = "rgba(231, 76, 60, 0.3)"; // Red spawn
            ctx.fillRect(this.spawnX * CELL_SIZE, this.spawnY * CELL_SIZE, CELL_SIZE, CELL_SIZE);

            // Draw Bots
            this.bots.forEach(bot => {
                ctx.beginPath();
                ctx.arc(
                    bot.x * CELL_SIZE + CELL_SIZE / 2,
                    bot.y * CELL_SIZE + CELL_SIZE / 2,
                    CELL_SIZE / 3,
                    0, Math.PI * 2
                );
                ctx.fillStyle = bot.finished ? "#95a5a6" : "#3498db";
                ctx.fill();
                ctx.strokeStyle = "white";
                ctx.lineWidth = 1;
                ctx.stroke();
            });
        }
    }

    const game = new MazeGame();
    window.game = game; // Expose to window for testing

    // Animation Loop
    function animate() {
        game.tick(1);
        game.render();
        requestAnimationFrame(animate);
    }
    requestAnimationFrame(animate);

    // Event Listeners
    resetBtn.addEventListener('click', () => game.reset());

})();
</script>
</body>
</html>
